#pragma warning disable CS1591, CS1573
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
namespace 
{
    [ApiController]
    [Route("api/[controller]")]
    public class UserController : ControllerBase
    {
        private readonly global::IUserService iUserService;
        public UserController(global::IUserService iUserService)
        {
            this.iUserService = iUserService;
        }

        [Route("GetUserName/{id}")]
        [HttpGet]
        public string GetUserName([FromRoute] int id)
        {
            return this.iUserService.GetUserName(id);                    
        }
    }
}

#pragma warning disable CS1591, CS1573
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
namespace 
{
    [ApiController]
    [Route("api/[controller]")]
    public class ProductController : ControllerBase
    {
        private readonly global::IProductService iProductService;
        public ProductController(global::IProductService iProductService)
        {
            this.iProductService = iProductService;
        }

        [Route("GetProductCount")]
        [HttpGet]
        public int GetProductCount()
        {
            return this.iProductService.GetProductCount();                    
        }
    }
}
